export const meta = {
  name: 'coffeegoddd-pr-sweep',
  description: "Review all 6 of coffeegoddd's open PRs on gastownhall/beads, classify, and list maintainer-fixable vs author-attention items",
  phases: [
    { title: 'Review', detail: 'one deep review agent per PR' },
    { title: 'Verify', detail: 'adversarial check of correctness findings per PR' },
  ],
}

const TARGET = budget.total ?? 200_000

const PRS = [
  { n: 5003, title: 'feat: support compact/gc/ping/dolt clean-databases in proxied-server mode', size: '+1039/-4', notes: 'Brand new (2026-07-23). mergeable=UNKNOWN at listing time. Touches proxied-server / storage surface.' },
  { n: 5002, title: 'bd sql (proxied-server): multi-statement batches and --database flag', size: '+313/-13', notes: 'Brand new (2026-07-23). MERGEABLE. Touches bd sql in proxied-server mode.' },
  { n: 4942, title: 'Bump Go to 1.26.5', size: '+4/-4', notes: 'Likely easy win; verify CI and that all version references are consistent (go.mod, CI workflows, Dockerfiles).' },
  { n: 4388, title: 'ci: run all tests, drop -short, add embedded job, pull Dolt image', size: '+7653/-5034', notes: 'From 2026-06-12. reviewDecision=CHANGES_REQUESTED, merge state DIRTY (needs rebase). Read the change-requesting review carefully and determine exactly what is outstanding and whether a maintainer can address it. Large diff likely includes stale merge-base churn: ALWAYS diff three-dot against merge-base.' },
  { n: 4372, title: 'metrics: instrument commands and migrate to GA4 via eventkit', size: '+7252/-5018', notes: 'From 2026-06-11, DIRTY (needs rebase). Product-surface change: read bd-main/docs/PROJECT_CHARTER.md and assess scope fit (telemetry). Large diff likely includes stale merge-base churn: diff three-dot against merge-base.' },
  { n: 4286, title: 'Split dependencies into six target-typed tables to fix Dolt merge conflicts', size: '+2134/-2000', notes: 'From 2026-06-01, DIRTY (needs rebase). Schema migration change by the storage-layer owner. Pay attention to migration ordering: in beads, schema migrations run at STORE OPEN in root PersistentPreRunE (cmd/bd/main.go), before any subcommand RunE. Check migration/backfill correctness and rebase burden.' },
]

const REVIEW_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  required: ['number', 'classification', 'summary', 'ci_status', 'rebase', 'unresolved_feedback', 'obvious_fixes', 'author_attention', 'correctness_findings', 'recommendation'],
  properties: {
    number: { type: 'integer' },
    classification: { type: 'string', description: 'one of: easy-win | merge | merge-fix | fix-merge | needs-review | retire | reject' },
    summary: { type: 'string', description: '2-4 sentences: what the PR does and its current state' },
    ci_status: { type: 'string', description: 'current check results on the PR head, naming failing workflows if any' },
    rebase: {
      type: 'object', additionalProperties: false,
      required: ['needed', 'commits_behind', 'conflicts_expected', 'conflict_areas'],
      properties: {
        needed: { type: 'boolean' },
        commits_behind: { type: 'integer' },
        conflicts_expected: { type: 'boolean' },
        conflict_areas: { type: 'array', items: { type: 'string' } },
      },
    },
    unresolved_feedback: { type: 'array', items: { type: 'string' }, description: 'each unresolved review thread / requested change, quoted or paraphrased, with who raised it' },
    obvious_fixes: {
      type: 'array',
      description: 'mechanical items a maintainer could fix on the contributor branch without design input: rebase, typos, lint, doc regen, small test fixes, trivial bugs',
      items: {
        type: 'object', additionalProperties: false,
        required: ['description', 'files', 'how'],
        properties: {
          description: { type: 'string' },
          files: { type: 'array', items: { type: 'string' } },
          how: { type: 'string', description: 'concrete steps a maintainer would take' },
        },
      },
    },
    author_attention: { type: 'array', items: { type: 'string' }, description: 'items genuinely needing coffeegoddd: design decisions, unresolved reviewer objections, ambiguous behavior' },
    correctness_findings: {
      type: 'array',
      items: {
        type: 'object', additionalProperties: false,
        required: ['file', 'issue', 'severity'],
        properties: {
          file: { type: 'string' },
          line: { type: 'integer' },
          issue: { type: 'string' },
          severity: { type: 'string', description: 'high | medium | low' },
        },
      },
    },
    recommendation: { type: 'string', description: 'recommended maintainer action per PR_MAINTAINER_GUIDELINES outcomes, with 1-2 sentence rationale' },
  },
}

const VERDICT_SCHEMA = {
  type: 'object', additionalProperties: false,
  required: ['verdicts'],
  properties: {
    verdicts: {
      type: 'array',
      items: {
        type: 'object', additionalProperties: false,
        required: ['issue', 'real', 'reason'],
        properties: {
          issue: { type: 'string', description: 'short restatement of the finding being judged' },
          real: { type: 'boolean' },
          reason: { type: 'string' },
        },
      },
    },
  },
}

const commonCtx = `
You are reviewing an open PR on gastownhall/beads as a maintainer's delegate. Context:
- cwd is /var/home/matt/dev/mybd (coordination repo). The beads source clone is at bd-main/ with remotes: origin = maphew/beads (fork), upstream = gastownhall/beads.
- The PR head is already fetched locally as ref upstream/pr/<N> in bd-main; upstream/main is current (800f4730b).
- The PR author coffeegoddd (Dustin Brown, DoltHub) is the beads STORAGE-LAYER owner and a trusted core contributor - review for substance, not for trust.
- Use ONLY read-only commands: gh (read ops), git -C bd-main log/diff/show/merge-base/rev-list. Do NOT run bd or dolt commands. Do NOT edit anything. Do NOT post anything to GitHub.
- Old PRs accumulate merge-base drift: compute REAL changes with three-dot semantics: MB=$(git -C bd-main merge-base upstream/main upstream/pr/<N>) then git -C bd-main diff --stat $MB upstream/pr/<N>, and read the actual changed files from the PR side.

Gather, in order:
1. gh pr view <N> --repo gastownhall/beads --json title,body,state,reviewDecision,mergeable,mergeStateStatus,statusCheckRollup
2. Full discussion: gh pr view <N> --repo gastownhall/beads --comments ; plus unresolved review threads via:
   gh api graphql -f query='query{repository(owner:"gastownhall",name:"beads"){pullRequest(number:<N>){reviewThreads(first:50){nodes{isResolved isOutdated path comments(first:10){nodes{author{login} body}}}}}}}'
3. Rebase burden: git -C bd-main rev-list --count upstream/pr/<N>..upstream/main and a trial: git -C bd-main merge-tree --write-tree --no-messages $(git -C bd-main merge-base upstream/main upstream/pr/<N>) upstream/main upstream/pr/<N> 2>&1 | head -30 (non-zero exit / CONFLICT lines => conflicts; list conflicted paths).
4. The real diff (three-dot as above): read every non-generated changed file's diff. Generated artifacts (docs/cli/*.md regen, .beads exports, vendored files) can be skimmed via --stat only.
5. Review the substance: correctness, tests present and meaningful, error handling, backward compatibility, docs. For anything touching store open/migrations, remember migrations run at store open in root PersistentPreRunE before RunE.

Then classify per the maintainer guidelines triage groups (easy-win / fix-merge / needs-review) and outcomes (merge / merge-fix / fix-merge / cherry-pick / needs-review / retire / reject). Distinguish sharply between "obvious_fixes" (mechanical, a maintainer can do on the contributor branch: rebases, typos, lint, regen, small clear bugs) and "author_attention" (needs the author's judgment). Your final output is ONLY the structured object.
`

phase('Review')
log(`Reviewing 6 open PRs from coffeegoddd; token target ${Math.round(TARGET / 1000)}k`)

const results = await pipeline(
  PRS,
  (pr) => {
    if (budget.spent() > TARGET * 0.85) { log(`skipping PR ${pr.n} review: budget nearly exhausted`); return null }
    const cheap = pr.n === 4942
    return agent(
      `${commonCtx}\nPR to review: #${pr.n} "${pr.title}" (${pr.size}).\nKnown context: ${pr.notes}\nReplace <N> with ${pr.n} in all commands.`,
      { label: `review:${pr.n}`, phase: 'Review', schema: REVIEW_SCHEMA, ...(cheap ? { model: 'haiku', effort: 'low' } : {}) }
    )
  },
  (review, pr) => {
    if (!review) return null
    const findings = (review.correctness_findings || []).filter(f => f.severity !== 'low')
    if (!findings.length) return review
    if (budget.spent() > TARGET) { log(`skipping verify for PR ${pr.n}: over budget`); return review }
    return agent(
      `${commonCtx}\nYou are an adversarial verifier for PR #${pr.n} "${pr.title}" on gastownhall/beads. A reviewer claims the following correctness issues in this PR's diff. For EACH claim, read the actual code (three-dot diff and surrounding context from ref upstream/pr/${pr.n}) and try to REFUTE it. Mark real=true only if the issue genuinely exists in the PR as written and would matter. Claims:\n${JSON.stringify(findings, null, 2)}`,
      { label: `verify:${pr.n}`, phase: 'Verify', schema: VERDICT_SCHEMA }
    ).then(v => ({ ...review, verified: v ? v.verdicts : null }))
  }
)

const out = results.filter(Boolean)
log(`Done: ${out.length}/6 PRs reviewed; spent ~${Math.round(budget.spent() / 1000)}k tokens`)
return out

